import React, { Fragment, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { graphql } from 'gatsby';
import { changeLocale, useIntl } from 'gatsby-plugin-intl';
import PropTypes from 'prop-types';
import { Collapse, Divider, TextField, Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import { commentsData } from '../utils/config';

// Components
import CommentForm from '../components/CommentForm';
import Comments from '../components/Comments';
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import Link from '../components/Link';
import RelatedPosts from '../components/RelatedPosts';

// Utils
import {
    getAlternateLangLinks,
    getCategoryPageUrlPath,
    getFormattedDateForLanguage,
    getTagPageUrlPath,
    setSnackbarMessage,
} from '../utils/gatsby-frontend-helpers';
import { WARNING_MESSAGE_TYPE } from '../utils/constants';

// Styles
import prismJsDark from '../themes/prismJsDark';
import prismJsLight from '../themes/prismJsLight';

const useStyles = makeStyles((theme) => ({
    blogPostWrapper: {
        '& .highlighted-text': {
            padding: '3px 2px',
            ...theme?.palette?.type === 'light' && {
                backgroundColor: '#edff5c',
                color: '#000000',
            },
            ...theme?.palette?.type === 'dark' && {
                backgroundColor: '#00909e',
                color: '#ffffff',
            },
        },
        '& a': {
            color: '#8da4f7',
        },
        '& a:visited': {
            color: '#48578a',
        },
        '& .embedVideo-iframe': {
            // class from gatsby-remark-embed-video
            padding: '10px 5%',
        },
        '& .gatsby-remark-local-videos': {
            // class from gatsby-remark-local-videos
            padding: '10px 5%',
        },
        '& .gatsby-highlight': {
            ...theme?.palette?.type === 'light' && prismJsDark,
            ...theme?.palette?.type === 'dark' && prismJsLight,
        },
        '& blockquote': {
            borderLeft: '10px solid #ccc',
            margin: '1.5em 10px',
            padding: '0.5em 10px',
            quotes: '"“" "”"',
            '&:before': {
                color: '#ccc',
                content: 'open-quote',
                fontSize: '4em',
                lineHeight: '0.1em',
                marginRight: '0.25em',
                verticalAlign: '-0.4em',
            },
        },
        '& .gatsby-resp-image-wrapper': {
            margin: '10px auto',
        },
        '& .language-text': {
            // ...theme?.palette?.type === 'light' && {
            //     backgroundColor: '#d5d6d8',
            // },
            // ...theme?.palette?.type === 'dark' && {
            //     backgroundColor: '#50545a',
            // },
            backgroundColor: '#d5d6d8',
            borderRadius: '5px',
            padding: '2px 3px',
            fontStyle: 'italic',
            color: '#8a8a8a',
            overflowWrap: 'break-word',
            wordWrap: 'break-word',
        },
        '& .gatsby-resp-image-figcaption': {
            fontStyle: 'italic',
            textAlign: 'center',
            marginTop: '-8px',
        },
        '& .gatsby-resp-image-figure': {
            margin: 'auto',
        },
        '& p > img:not([class])': {
            margin: 'auto',
            display: 'block',
            // width: '100%',
            maxWidth: 'min(1024px, 100%)',
        },
    },
    breadcrumb: {
        fontStyle: 'italic',
        marginTop: '10px',
        ...theme?.palette?.type === 'light' && {
            color: '#636363',
            '& a': {
                color: '#636363',
            },
            '& a:visited': {
                color: '#636363',
            },
        },
        ...theme?.palette?.type === 'dark' && {
            color: '#adadad',
            '& a': {
                color: '#adadad',
            },
            '& a:visited': {
                color: '#adadad',
            },
        },
    },
    blogTitleText: {
        fontSize: '1.5rem;',
    },
    blogPostContent: {
        padding: '0 5px',
    },
    commentForm: {
        margin: '0 0 20px',
    },
    comments: {
        margin: '10px 0',
    },
    postCommentCta: {
        margin: '0 0 20px',
    },
    postACommentText: {
        marginTop: '10px',
    },
    tagsWrapper: {
        padding: '0',
        margin: '0',
    },
    tagsListItem: {
        display: 'inline',
        listStyle: 'none',
        padding: '0',
        '&::after': {
            content: '", "',
        },
        '&:last-child::after': {
            content: '""',
        },
    },
}));

const BlogPostTemplate = ({ data, pageContext, location }) => {
    const { markdownRemark, categoryImage } = data;
    const {
        title,
        allowComments,
        categories,
        date,
        path: postPath,
        tags,
    } = markdownRemark.frontmatter;
    const category = categories[0];
    const { slug, path, locale, postHashId, readingTime } = markdownRemark.fields;
    // const { previous, next } = pageContext;
    const {
        googleFormData,
        comments,
        images,
        videos,
        otherLanguagesUrl,
        relatedPosts,
    } = pageContext;
    const [previous, next] = [false, false]; // TODO
    const classes = useStyles();
    const [isShowingCommentsForm, setIsShowingCommentsForm] = useState(false);
    const isFocusingOnComment = useRef(false);
    const intl = useIntl();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    useEffect(() => {
        isFocusingOnComment.current = false;
    }, [isShowingCommentsForm]);

    const handleLanguageChange = useCallback((newLanguage, currentLanguage) => {
        const newPath = otherLanguagesUrl
            .find((p) => p.startsWith(`/${newLanguage}/`));

        if (newPath) {
            changeLocale(newLanguage, newPath.replace(`/${newLanguage}/`, '/'));
        } else {
            setSnackbarMessage('sorry_this_post_unavailable_language', WARNING_MESSAGE_TYPE);
            changeLocale(newLanguage, '/blog');
        }
    }, [otherLanguagesUrl]);

    return (
        <Layout
            showLanguageSelector={otherLanguagesUrl?.length > 0}
            onLanguageChange={handleLanguageChange}
        >
            <SEO
                robots={
                    new Date().toISOString() >= date
                    && 'noindex, nofollow'
                }
                lang={intl.locale}
                pathname={location?.pathname}
                title={title}
                description={markdownRemark.excerpt}
                keywords={tags}
                ogImage={images[0]}
                alternativeOgImage={categoryImage?.childImageSharp?.original?.src}
                ogVideo={videos[0]}
                alternateLangLinks={alternateLangLinks}
            />
            <div className={classes.blogPostWrapper}>
                <article>
                    <header>
                        <div className={classes.breadcrumb}>
                            <Link
                                to="/blog"
                            >
                                {intl.formatMessage({ id: 'blog' })}
                            </Link>
                            {' → '}
                            <Link
                                to={getCategoryPageUrlPath(category)}
                            >
                                {intl.formatMessage({ id: `blog_categories.${category}` })}
                            </Link>
                            {' → '}
                        </div>
                        <Typography
                            className={classes.blogTitleText}
                            color="textPrimary"
                        >
                            {title}
                        </Typography>
                        <Typography
                            color="textSecondary"
                            variant="body2"
                            component="small"
                        >
                            {intl.formatMessage({ id: 'written_in' })}
                            {getFormattedDateForLanguage(date, intl.locale)}
                            {' - '}
                            {intl.formatMessage({ id: 'read_time' }, {
                                time: Math.round(readingTime.minutes) || 1,
                            })}
                        </Typography>
                    </header>
                    <section
                        className={classes.blogPostContent}
                        dangerouslySetInnerHTML={{ __html: markdownRemark.html }}
                    />
                    {tags?.length > 0 && (
                        <Fragment>
                            <Typography
                                color="textPrimary"
                            >
                                {intl.formatMessage({ id: 'tags_colon' })}
                            </Typography>
                            <ul
                                className={classes.tagsWrapper}
                            >
                                {tags.map((tag) => (
                                    <li
                                        className={classes.tagsListItem}
                                        key={tag}
                                    >
                                        <Link
                                            to={getTagPageUrlPath(tag)}
                                        >
                                            {tag}
                                        </Link>
                                    </li>
                                ))}
                            </ul>
                        </Fragment>
                    )}
                </article>
                <nav>
                    <ul>
                        {previous && (
                            <li>
                                <Link to={previous.fields.path} rel="prev">
                                    ← {previous.frontmatter.title}
                                </Link>
                            </li>
                        )}
                        {next && (
                            <li>
                                <Link to={next.fields.path} rel="next">
                                    {next.frontmatter.title} →
                                </Link>
                            </li>
                        )}
                    </ul>
                </nav>
                {relatedPosts?.length > 0 && (
                    <RelatedPosts
                        relatedPosts={relatedPosts}
                        quantity={3}
                    />
                )}
                <div>
                    {allowComments && (
                        <Fragment>
                            <Divider />
                            <Typography
                                className={classes.postACommentText}
                                color="textSecondary"
                                variant="h6"
                            >
                                {intl.formatMessage({ id: 'post_a_comment' })}
                            </Typography>
                            {!isShowingCommentsForm && (
                                <div className={classes.postCommentCta}>
                                    <TextField
                                        label={intl.formatMessage({ id: 'comment' })}
                                        onFocus={() => {
                                            setIsShowingCommentsForm(true);
                                            isFocusingOnComment.current = true;
                                        }}
                                    />
                                </div>
                            )}
                            <Collapse in={isShowingCommentsForm}>
                                <CommentForm
                                    className={classes.commentForm}
                                    googleFormId={commentsData.googleFormId}
                                    googleFormData={googleFormData}
                                    postPath={postPath}
                                    focusOnComment={isFocusingOnComment?.current && isShowingCommentsForm}
                                />
                            </Collapse>
                            <Divider />
                            <Comments
                                comments={comments}
                                className={classes.comments}
                            />
                        </Fragment>
                    )}
                </div>
            </div>
        </Layout>
    );
};

BlogPostTemplate.propTypes = {
    pageContext: PropTypes.object.isRequired,
    location: PropTypes.object.isRequired,
    data: PropTypes.shape({
        markdownRemark: PropTypes.shape({
            frontmatter: PropTypes.object.isRequired,
            fields: PropTypes.object.isRequired,
            excerpt: PropTypes.string.isRequired,
            html: PropTypes.string.isRequired,
            id: PropTypes.string.isRequired,
        }).isRequired,
        site: PropTypes.shape({
            siteMetadata: PropTypes.shape({
                siteUrl: PropTypes.string.isRequired,
            }).isRequired,
        }).isRequired,
    }).isRequired,
};

export default BlogPostTemplate;

export const pageQuery = graphql`
    query BlogPostBySlug($slug: String!, $categoryImage: String) {
        site {
            siteMetadata {
                siteUrl
            }
        }
        markdownRemark(fields: { slug: { eq: $slug } }) {
            id
            excerpt(pruneLength: 160)
            html
            fields {
                postHashId
                slug
                path
                locale
                readingTime {
                    minutes
                }
            }
            frontmatter {
                path
                allowComments
                title
                date
                categories
                tags
                hideExcerpt
            }
        }
        categoryImage: file(absolutePath: { regex: $categoryImage }) {
            childImageSharp {
                original {
                    width
                    height
                    src
                }
            }
        }
    }
`;
