import React from 'react';
import PropTypes from 'prop-types';
import { Card, Typography } from '@material-ui/core';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
    relatedPostsWrapper: {
        marginBottom: '10px',
    },
    relatedPostWrapper: {
        cursor: 'pointer',
        '& a': {
            textDecoration: 'none',
            '&:hover': {
                textDecoration: 'underline',
            },
        },
        [theme.breakpoints.up(760)]: {
            width: '32%',
            display: 'inline-block',
            marginRight: '1.5%',
            '&:last-child': {
                marginRight: '0.5%',
            },
            '&:first-child': {
                marginLeft: '0.5%',
            },
        },
        [theme.breakpoints.down(760)]: {
            width: '100%',
            margin: '5px',
        },
    },
    relatedPostCard: {
        padding: '10px',
    },
}));

function RelatedPosts({
    relatedPosts,
    quantity,
    className = null,
}) {
    const intl = useIntl();
    const classes = useStyles();
    let postsLoop = relatedPosts;
    if (quantity) {
        postsLoop = postsLoop.slice(0, quantity);
    }

    return (
        <div
            className={className}
        >
            <Typography
                color="textSecondary"
                variant="h6"
            >
                {intl.formatMessage({ id: 'related_posts' })}
            </Typography>
            <div className={classes.relatedPostsWrapper}>
                {postsLoop.map((relatedPost, index) => {
                    const { fields, frontmatter } = relatedPost;
                    const { path, postHashId, locale } = fields;
                    const { title } = frontmatter;
                    return (
                        <div
                            key={postHashId}
                            className={classes.relatedPostWrapper}
                        >
                            <a
                                href={`/${locale}${path}`}
                            >
                                <Card
                                    className={classes.relatedPostCard}
                                >
                                    <Typography
                                        color="textSecondary"
                                        variant="body1"
                                    >
                                        {title}
                                    </Typography>
                                </Card>
                            </a>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

RelatedPosts.propTypes = {
    className: PropTypes.string,
    relatedPosts: PropTypes.arrayOf(PropTypes.shape({
        // TODO
    })),
};

export default RelatedPosts;
