export default {
    '& code[class*="language-"], pre[class*="language-"]': {
        textAlign: 'left',
        whiteSpace: 'pre',
        wordSpacing: 'normal',
        wordBreak: 'normal',
        wordWrap: 'normal',
        hyphens: 'none',
        color: 'inherit',
        textShadow: 'none',
        fontFamily: 'Roboto Mono, monospace',
        fontSize: '1em',
        lineHeight: '1.5em',
        tabSize: '4',
    },
    '& code[class*="language-"]::-moz-selection, pre[class*="language-"]::-moz-selection,\ncode[class*="language-"] ::-moz-selection,\npre[class*="language-"] ::-moz-selection': {
        textShadow: 'none',
        opacity: '1',
        color: '#eee',
        background: '#363636',
    },
    '& code[class*="language-"]::selection, pre[class*="language-"]::selection,\ncode[class*="language-"] ::selection,\npre[class*="language-"] ::selection': {
        textShadow: 'none',
        opacity: '1',
        color: '#eee',
        background: '#363636',
    },
    '& @media print': {
        '& code[class*="language-"], pre[class*="language-"]': {
            textShadow: 'none !important',
        },
    },
    '& :not(pre) > code[class*="language-"]': {
        whiteSpace: 'normal',
        color: '#eee',
        background: '#333333c2', // 2f2f2f
        borderRadius: '0.2em',
        padding: '0.1em',
    },
    '& pre > code[class*="language-"]': { background: 'none' },
    '& pre[class*="language-"]': {
        overflow: 'auto',
        position: 'relative',
        color: '#eee',
        background: '#333333c2', // 2f2f2f
        borderRadius: '0',
        margin: '0.5em 0',
        padding: '1.25em 1em',
    },
    '& pre[class*="language-"].language-css > code, pre[class*="language-"].language-sass > code, pre[class*="language-"].language-scss > code': {
        color: '#fd9170',
    },
    '& [class*="language-"] .namespace': { opacity: '0.7' },
    '& .token.atrule': { color: '#c792ea' },
    '& .token.attr-name': { color: '#ffcb6b' },
    '& .token.attr-value': { color: '#a5e844' },
    '& .token.attribute': { color: '#a5e844' },
    '& .token.boolean': { color: '#c792ea' },
    '& .token.builtin': { color: '#ffcb6b' },
    '& .token.cdata': { color: '#80cbc4' },
    '& .token.char': { color: '#80cbc4' },
    '& .token.class': { color: '#ffcb6b' },
    '& .token.class-name': { color: '#f2ff00' },
    '& .token.comment': { color: '#a0a0a0' },
    '& .token.constant': { color: '#c792ea' },
    '& .token.deleted': { color: '#ff6666' },
    '& .token.doctype': { color: '#a0a0a0' },
    '& .token.entity': { color: '#ff6666' },
    '& .token.function': { color: '#c792ea' },
    '& .token.hexcode': { color: '#f2ff00' },
    '& .token.id': { color: '#c792ea', fontWeight: 'bold' },
    '& .token.important': { color: '#c792ea', fontWeight: 'bold' },
    '& .token.inserted': { color: '#80cbc4' },
    '& .token.keyword': { color: '#c792ea' },
    '& .token.number': { color: '#fd9170' },
    '& .token.operator': { color: '#89ddff' },
    '& .token.prolog': { color: '#a0a0a0' },
    '& .token.property': { color: '#80cbc4' },
    '& .token.pseudo-class': { color: '#a5e844' },
    '& .token.pseudo-element': { color: '#a5e844' },
    '& .token.punctuation': { color: '#89ddff' },
    '& .token.regex': { color: '#f2ff00' },
    '& .token.selector': { color: '#ff6666' },
    '& .token.string': { color: '#a5e844' },
    '& .token.symbol': { color: '#c792ea' },
    '& .token.tag': { color: '#ff6666' },
    '& .token.unit': { color: '#fd9170' },
    '& .token.url': { color: '#ff6666' },
    '& .token.variable': { color: '#ff6666' },
};
